import{_ as r,H as t,f as s,i as a}from"./chunks/framework.CrrulRN2.js";const o="/makcodeBlog/assets/vercel0.D4KUIO3-.png",n="/makcodeBlog/assets/vercel1.7czxL08f.png",h=JSON.parse('{"title":"what is vercel and serverless functions","description":"سرور مفتکی!!","frontmatter":{"title":"what is vercel and serverless functions","description":"سرور مفتکی!!","date":"2026-05-30T00:00:00.000Z","author":"makcodeir"},"headers":[],"relativePath":"posts/vercel.md","filePath":"posts/vercel.md"}'),l={name:"posts/vercel.md"};function c(i,e,p,d,_,f){return t(),s("div",null,[...e[0]||(e[0]=[a('<h1 id="vercel" tabindex="-1">vercel <a class="header-anchor" href="#vercel" aria-label="Permalink to &quot;vercel&quot;">​</a></h1><p>یک پلتفرم برای دپلوی پروژه های مختلف هست، میشه سایت های استاتیک رو روش قرار داد(رایگان) و یا serverless function ها رو روش قرار داد و من یک <a href="https://rtlmarkdown.vercel.app/" target="_blank" rel="noreferrer">ادیتور مارک دوون</a> که با جاوااسکریپت وانیلا ساخته شده رو داخلش قرار دادم!! البته که پلتفرم های زیادی برای قرار دادن ابزار های استاتیک وجود داره مثل گیت هاب پیجز و cloudflare و ... وجود داره که رایگان هم هستن و فقط باید کد <strong>html/css/js</strong> رو داخلشون بزاری و خب چیز عجیب و غریبی نیستن!(کاش تو ایران هم همچین سرویسی می بود !! واقعا کم هزینه هست(حداقل برای شرکت هایی که این همه سرور دارن!!))</p><img src="'+o+'" alt="Page" width="660" data-align="center"><p>میخوام بیشتر درباره serverless function صحبت کنم ! بیاین به این مثال توجه کنید : شما یک وبسایت استاتیک ساختید چون که نمی خواید هزینه یک هاست خیلی گرون رو بدید D: و به راحتی توی پلتفرم هایی که بالا گفتم و اون دوستمون توی تصویر داره بهشون فکر میکنه استفاده کنید، ولی این ابزار ها یک مشکلی دارن.....</p><hr><p>بک اند ندارن... &lt;:</p><hr><p>قاعدتا خیلی از وبلاگ ها و خیلی از ابزار ها به بک اند خاصی نیاز ندارن و به راحتی سمت کلاینت اجرا میشن.</p><p>ولی آیا برای پیاده سازی یک منطق ساده ، نیاز به بالا اومدن یک بک اند کامل هست !!! فرض کنید یک فرم ارتباط با ما دارید افراد میتونن نظراتشون رو بنویسن و با ایمیل شما ارسال بشه و یک منطق خیلی ساده ، مثلا جلوگیری از اسپم رو پیاده سازی کنه ! خب نیازی نیست که یک سرور کامل حتی با مشخصات خیلی کم بخریم ، صرفا به یک function نیاز داریم ! سرویس های مثلا کلادفلر و ورسل این قابلیت رو به ما میدن که یک serverless function داشته باشیم که همچین منطق ساده ای رو پیاده سازی کنه !</p><img src="'+n+'" alt="Page" width="660" data-align="center"> *** یا میتونیم ازش برای وبهوک استفاده کنیم ، مثلا بات تلگرام برای ارتباط با یوزر دو راه داره : ۱-polling 2-webhook در روش اول ربات همش داره چک میکنه که درخواستی ارسال شده یا نه !!(منطقی به نظر نمیاد نه ؟) در روش دوم منتظر وایمیسه که یک چیزی به اسم webhook بهش خبر بده که فلانی درخواست ارسال کرده و درخواستش چی بوده <p>در روش اول سخت افزار 24 ساعته باید فال گوش وایسته و هی پرس و جو کنه در روش دوم صرفا از یک serverless function مفتکی استفاده کردیم و سخت افزار ما هر وقت درخواستش بیاد اون رو پردازش میکنه. حتی خود بات تلگرامم میشه داخلش قرار داد(هر چند که فکر میکنم خیلی کار سختی باشه شاید یک روز در قالب یک پروژه انجامش دادم)</p>',12)])])}const m=r(l,[["render",c]]);export{h as __pageData,m as default};
